import React, { useRef, useEffect } from 'react';
import 'ol/ol.css';

import MapOL from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import OSM from 'ol/source/OSM';
import { fromLonLat } from 'ol/proj';
import XYZ from 'ol/source/XYZ';

import './Map.css';

const Map = props => {
  const mapRef = useRef();
  const mapInstance = useRef(); // 🔥 important

  const { center, zoom } = props;

 useEffect(() => {
  if (!mapInstance.current) {
    // मैप पहली बार लोड करने के लिए
    mapInstance.current = new MapOL({
      target: mapRef.current,
      layers: [new TileLayer({ source: new OSM() })], // या XYZ ऊपर वाला
      view: new View({
        center: fromLonLat([center.lng, center.lat]),
        zoom: zoom
      })
    });
  } else {
    // लोकेशन बदलने पर मैप को वहां ले जाने के लिए
    const view = mapInstance.current.getView();
    view.setCenter(fromLonLat([center.lng, center.lat]));
    view.setZoom(zoom);
  }
}, [center, zoom]);

  return (
    <div
      ref={mapRef}
      className={`map ${props.className}`}
      style={props.style}
      onClick={(e) => e.stopPropagation()}
    />
  );
};

export default Map;
